import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/Dashboard.css';


function Dashboard() {
  const navigate = useNavigate();
  const [userName, setUserName] = useState('');
  const [asthmaStatus, setAsthmaStatus] = useState('Normal');
  const [timeFrame, setTimeFrame] = useState('30');
  const [riskScore, setRiskScore] = useState(0);
  const [lastCheckDate, setLastCheckDate] = useState('');
  const [recentSymptoms, setRecentSymptoms] = useState([]);
  const [medicationAdherence, setMedicationAdherence] = useState(0);
  const [triggerExposure, setTriggerExposure] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [userRole, setUserRole] = useState('user');
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showAnimation, setShowAnimation] = useState(false);

  // Завантаження даних при першому відкритті
  useEffect(() => {
    fetchUserData();
    fetchAsthmaStatus();
    checkUserRole();
  }, []);

  // Оновлення статусу астми при зміні часового періоду
  useEffect(() => {
    fetchAsthmaStatus();
  }, [timeFrame]);

  // Перевірка ролі користувача (адмін чи звичайний користувач)
  const checkUserRole = async () => {
    try {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      const response = await fetch(`http://localhost:5000/api/user-role/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to verify user role');
      }

      const data = await response.json();
      setUserRole(data.role || 'user');
    } catch (error) {
      console.error('Error checking user role:', error);
      setUserRole('user');
    }
  };

  // Завантаження основних даних користувача
  const fetchUserData = async () => {
    try {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      const response = await fetch(`http://localhost:5000/api/users/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to fetch user data');
      }

      const data = await response.json();
      setUserName(data.fullname || 'User');

      // Також завантажуємо останні симптоми
      await fetchRecentSymptoms(user_id);
      // Та дані про прийом медикаментів
      await fetchMedicationAdherence(user_id);

    } catch (error) {
      console.error('Error fetching user data:', error);
      setError('Failed to load user data');
    } finally {
      setIsLoading(false);
    }
  };

  // Завантаження статусу астми за вибраний період
  const fetchAsthmaStatus = async () => {
    try {
      const user_id = localStorage.getItem('user_id');
      if (!user_id) {
        navigate('/');
        return;
      }

      const response = await fetch(`http://localhost:5000/api/asthma-status/${user_id}?days=${timeFrame}`);
      if (!response.ok) {
        throw new Error('Failed to fetch asthma status');
      }

      const data = await response.json();

      // Встановлюємо статус астми та інші показники
      setAsthmaStatus(data.status || 'Normal');
      setRiskScore(data.risk_score || 0);
      setLastCheckDate(data.last_check_date || '');
      setTriggerExposure(data.trigger_exposure || false);

    } catch (error) {
      console.error('Error fetching asthma status:', error);
      setError('Failed to load asthma status');
    }
  };

  // Завантаження останніх симптомів
  const fetchRecentSymptoms = async (user_id) => {
    try {
      const response = await fetch(`http://localhost:5000/api/recent-symptoms/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to fetch recent symptoms');
      }

      const data = await response.json();
      setRecentSymptoms(data.symptoms || []);

    } catch (error) {
      console.error('Error fetching recent symptoms:', error);
    }
  };

  // Завантаження даних про прийом медикаментів
  const fetchMedicationAdherence = async (user_id) => {
    try {
      const response = await fetch(`http://localhost:5000/api/medication-adherence/${user_id}`);
      if (!response.ok) {
